mapper.select:
SELECT /* dupLike */
       COUNT(*)
  FROM TB_LIKEXX
 WHERE USER_NUMB = #{userNumb}
   AND TAGT_TYPE = #{tagtType}
   AND TAGT_NUMB = #{tagtNumb}

mapper.insert:
/* setLike */
INSERT INTO TB_LIKEXX(
            USER_NUMB
          , TAGT_TYPE
          , TAGT_NUMB
          , REGI_DATE
) VALUES(   #{userNumb}
          , #{tagtType}
          , #{tagtNumb}
          , SYSDATE
)

mapper.delete:
